using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var notepad = new Notepad();
var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearch.SearchAsync,
        name: "web_search",
        description: "Search the web for information on a query. Returns a list of result snippets."),
    AIFunctionFactory.Create(notepad.AddNote,
        name: "add_note",
        description: "Save a research note for later reference."),
    AIFunctionFactory.Create(notepad.GetNotes,
        name: "get_notes",
        description: "Retrieve all saved research notes."),
};

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

var agent = new ChatClientAgent(
    chatClient,
    instructions: $"""
        You are a research agent. Research the topic thoroughly by following these steps:
        1. Run 3-5 different web searches covering different aspects of the topic.
        2. After each search, save the most important findings as notes using the add_note tool.
        3. Once you have gathered enough information, retrieve your notes with get_notes.
        4. Write a well-structured summary with sections, citing key facts from your research.
        Be factual and concise.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking tools.",
    tools: tools);

var session = await agent.CreateSessionAsync();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Please research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
        Console.Write(update.Text);
}

Console.WriteLine("\n\n✅ Research complete.");

if (notepad.Notes.Count > 0)
{
    Console.WriteLine($"\n--- Collected Notes ({notepad.Notes.Count}) ---");
    for (var i = 0; i < notepad.Notes.Count; i++)
        Console.WriteLine($"  {i + 1}. {notepad.Notes[i]}");
}

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------

/// <summary>Searches the web using DuckDuckGo HTML lite and returns result snippets.</summary>
static class WebSearch
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
    };

    public static async Task<string> SearchAsync(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await Http.GetStringAsync(url, cancellationToken);

            var snippets = ExtractSnippets(html);
            if (snippets.Count == 0)
                return "No results found.";

            return string.Join("\n\n", snippets.Take(5)
                .Select((s, i) => $"[{i + 1}] {s}"));
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static List<string> ExtractSnippets(string html)
    {
        var snippets = new List<string>();
        const string snippetStart = "class=\"result__snippet\"";

        var pos = 0;
        while ((pos = html.IndexOf(snippetStart, pos, StringComparison.Ordinal)) >= 0)
        {
            var tagEnd = html.IndexOf('>', pos);
            if (tagEnd < 0) break;

            var closeTag = html.IndexOf("</", tagEnd, StringComparison.Ordinal);
            if (closeTag < 0) break;

            var text = html[(tagEnd + 1)..closeTag];
            text = System.Text.RegularExpressions.Regex.Replace(text, "<[^>]+>", "");
            text = System.Net.WebUtility.HtmlDecode(text).Trim();

            if (text.Length > 0)
                snippets.Add(text);

            pos = closeTag;
        }

        return snippets;
    }
}

/// <summary>In-memory notepad for the agent to collect research findings.</summary>
class Notepad
{
    public List<string> Notes { get; } = [];

    public string AddNote(
        [Description("The research note to save")] string note)
    {
        Notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({Notes.Count} total)");
        return $"Note saved. You now have {Notes.Count} note(s).";
    }

    public string GetNotes()
    {
        if (Notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n", Notes.Select((n, i) => $"[{i + 1}] {n}"));
    }
}

